import { useState } from 'react';


export default function CreateDestination({ onClose }) {
    const [name, setName] = useState('');
    const [image, setImage] = useState('');
    const [price, setPrice] = useState('');
    const [startDate, setStartDate] = useState('');
    const [endDate, setEndDate] = useState('');
    const [creator, setCreator] = useState('');
    const [error, setError] = useState('');

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError('');

        if (!name || !image || !price || !startDate || !endDate || !creator) {
            setError('Tous les champs sont obligatoires.');
            return;
        }

        try {
            await createDestination({
                name,
                image,
                price,
                startDate,
                endDate,
                creator,
                members: [],
                comments: []
            });
            onClose();
        } catch (err) {
            console.error(err);
            setError("Erreur lors de la création.");
        }
    };

    return (
        <form className="create-group-form" onSubmit={handleSubmit}>
            <h2>Nouvelle destination</h2>

            <label>Nom</label>
            <input value={name} onChange={(e) => setName(e.target.value)} required />

            <label>Image (URL)</label>
            <input value={image} onChange={(e) => setImage(e.target.value)} required />

            <label>Prix (€)</label>
            <input
                type="number"
                value={price}
                onChange={(e) => setPrice(e.target.value)}
                required
            />

            <label>Date de début</label>
            <input
                type="date"
                value={startDate}
                onChange={(e) => setStartDate(e.target.value)}
                required
            />

            <label>Date de fin</label>
            <input
                type="date"
                value={endDate}
                onChange={(e) => setEndDate(e.target.value)}
                required
            />

            <label>Proposé par</label>
            <input
                type="text"
                value={creator}
                onChange={(e) => setCreator(e.target.value)}
                required
            />

            {error && <p className="login-error">{error}</p>}

            <button type="submit" className="create-group-button">
                Créer
            </button>
        </form>
    );
}
